export function getMortgageServiceBySlug(slug) {
  return MORTGAGE_SERVICES.find((s) => s.slug === slug) || null;
}

export function getRelatedMortgageServices(slug, count = 3) {
  const current = getMortgageServiceBySlug(slug);
  if (!current) return [];
  const sameCategory = MORTGAGE_SERVICES.filter(
    (s) => s.slug !== slug && s.category === current.category,
  );
  const others = MORTGAGE_SERVICES.filter(
    (s) => s.slug !== slug && s.category !== current.category,
  );
  return [...sameCategory, ...others].slice(0, count);
}
